console.log("1) أنا أولًا");

setTimeout(() => {
  console.log("3) أنا بعد ثانيتين");
}, 2000);

console.log("2) أنا لم أنتظر المؤقت!");

let remaining = 5;

const timerId = setInterval(() => {
  console.log("باقي:", remaining);
  remaining--;
  if (remaining < 0) {
    clearInterval(timerId); // أوقف نفسك
    console.log("🚀 انطلاق!");
  }
}, 700);

function tick() {
  const now = new Date();
  const h = String(now.getHours()).padStart(2, "0");
  const m = String(now.getMinutes()).padStart(2, "0");
  const s = String(now.getSeconds()).padStart(2, "0");
  document.querySelector("#clock").textContent = `${h}:${m}:${s}`;
}

tick();                  // عرض فوري
setInterval(tick, 1000); // ثم تحديث كل ثانية
